import { writeOutput } from "./codegen";

const DOCS_URL = "https://duffel.com/docs/api";
const PLACEHOLDER_VALUE = "duffel_test_CoffeeSafeLocalCoffeeSafeLocalCoffeeSa";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from Duffel API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:duffel",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../firewall-types";',
    "",
    "export const duffelFirewall = {",
    '  name: "duffel",',
    '  description: "Duffel",',
    "  placeholders: {",
    `    DUFFEL_TOKEN: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://api.duffel.com",',
    "      auth: {",
    "        headers: {",
    '          Authorization: "Bearer ${{ secrets.DUFFEL_TOKEN }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];
  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating Duffel firewall config...");
  const ts = generateTypeScript();
  writeOutput("duffel", ts, import.meta.dirname);
}
